from functools import lru_cache, partial, wraps

@lru_cache(maxsize=128)
def expensive_func(x):
    return x * x

def base_func(a, b, c):
    return a + b + c

partial_func = partial(base_func, 1, 2)

def decorator(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        return func(*args, **kwargs)
    return wrapper
